6	  expanded: boolean;
7	  onActivate: () => void;
8	  onFocusInto: () => void;
9	};
10	
11	// Spine content: ONLY the vertical title. No number, no three-letter code.
12	// Title is the exclusive identifier.
13	export default function PanelSpine({ panel, expanded, onActivate, onFocusInto }: Props) {
14	  const titleStack = panel.title.toUpperCase().split("").join("\n");
15	  return (
16	    <button
17	      type="button"
18	      role="button"
19	      aria-expanded={expanded}
20	      aria-controls={`panel-body-${panel.id}`}
21	      onClick={onActivate}
22	      onFocus={onFocusInto}
23	      className="panel-spine"
24	      style={{
25	        background: "transparent",
26	        color: "var(--fg-mute)",
27	        fontFamily: "var(--font-mono)",
28	        height: "100%",
29	        width: "100%",
30	        display: "flex",
31	        cursor: "pointer",
32	      }}
33	    >
34	      <span
35	        className="spine-content"
36	        style={{
37	          display: "flex",
38	          alignItems: "flex-start",
39	          justifyContent: "center",
40	          height: "100%",
41	          width: "100%",
42	          paddingTop: "var(--s-5)",
43	        }}
44	      >
45	        <span
46	          aria-hidden="true"
47	          style={{
48	            whiteSpace: "pre",
49	            fontSize: "var(--t-xs-size)",
50	            color: "var(--fg-dim)",
51	            textAlign: "center",
52	            lineHeight: 1.1,
53	            letterSpacing: "0.04em",
54	          }}
55	        >
56	          {titleStack}
