15	import GatesMode from "./coherenceEngine/GatesMode";
16	import CeAuditMode from "./coherenceEngine/AuditMode";
17	
18	function regimeFor(width: number): "narrow" | "standard" | "wide" {
19	  if (width < 640) return "narrow";
20	  if (width < 960) return "standard";
21	  return "wide";
22	}
23	
24	export default function HivemindExperience({ ctx }: { ctx: ExperienceContext }) {
25	  const hvmMode = useHvm((s) => s.mode);
26	  const ceMode = useCe((s) => s.mode);
27	  const regime = regimeFor(ctx.hostWidthPx);
28	
29	  // active face: rerender on face-change events
30	  const [face, setFace] = useState<"strategic" | "technical">(() => getActiveFace());
31	  useEffect(() => {
32	    function on(e: Event) {
33	      const det = (e as CustomEvent).detail as "strategic" | "technical";
34	      setFace(det);
35	    }
36	    window.addEventListener("hvm:face-change", on);
37	    return () => window.removeEventListener("hvm:face-change", on);
38	  }, []);
39	
40	  useEffect(() => {
