      <section id="principles-graph" style={{ marginBottom: "var(--s-7)" }}>
        <h2 style={{ fontFamily: "var(--font-mono)", color: "var(--fg-mute)", marginBottom: "var(--s-3)" }}>── PRINCIPLE GRAPH ──</h2>
        <PrincipleGraph principles={principles} />
      </section>
      <section id="noosphere" style={{ marginBottom: "var(--s-7)" }}>
        <h2 style={{ fontFamily: "var(--font-mono)", color: "var(--fg-mute)", marginBottom: "var(--s-3)" }}>── NOOSPHERE ──</h2>
        <NoosphereConsole feed={feed} viewing={3} />
      </section>
      <section id="principles" style={{ marginBottom: "var(--s-7)" }}>
        <h2 style={{ fontFamily: "var(--font-mono)", color: "var(--fg-mute)", marginBottom: "var(--s-3)" }}>── FIRST PRINCIPLES ({principles.length}) ──</h2>
        <PrinciplesList principles={principles} />
